svg.script:
(function(){
var root=document.documentElement;
var knob=document.getElementById('step-knob');
var rail=document.getElementById('step-rail');
var label=document.getElementById('step-label');
if(!root||!knob||!rail||!label) return;
var maxStep=9;
var current=4;
var dragging=false;
function q(sel){return Array.prototype.slice.call(root.querySelectorAll(sel));}
function railBounds(){return {x0:parseFloat(rail.getAttribute('data-x0')),x1:parseFloat(rail.getAttribute('data-x1')),y:parseFloat(rail.getAttribute('data-y'))};}
function toPoint(evt){var pt=root.createSVGPoint();pt.x=evt.clientX;pt.y=evt.clientY;return pt.matrixTransform(root.getScreenCTM().inverse());}
function clampStep(v){if(v<0) return 0;if(v>maxStep) return maxStep;return v;}
function applyState(step){
 current=clampStep(step);
 q('[data-step-role]').forEach(function(el){var rank=parseInt(el.getAttribute('data-step-rank')||'-1',10);var active=rank>=0&&rank<=current;el.setAttribute('class',active?el.getAttribute('data-step-active-class'):el.getAttribute('data-step-pending-class'));});
 q('[data-step-dot]').forEach(function(dot){var idx=parseInt(dot.getAttribute('data-step-dot')||'0',10);dot.setAttribute('class',idx===current?'step-dot active':'step-dot');});
 var b=railBounds(); var x=maxStep>0?b.x0+((current/maxStep)*(b.x1-b.x0)):b.x0; knob.setAttribute('cx',x); knob.setAttribute('cy',b.y); label.textContent='step '+(current+1)+'/10';
}
function stepFromEvent(evt){var p=toPoint(evt);var b=railBounds();if(maxStep<=0) return 0;return clampStep(Math.round(((p.x-b.x0)/(b.x1-b.x0))*maxStep));}
function startDrag(evt){dragging=true;knob.setAttribute('class','step-knob dragging');applyState(stepFromEvent(evt));evt.preventDefault();}
function moveDrag(evt){if(!dragging) return;applyState(stepFromEvent(evt));evt.preventDefault();}
function endDrag(){dragging=false;knob.setAttribute('class','step-knob');}
rail.addEventListener('pointerdown',startDrag);
knob.addEventListener('pointerdown',startDrag);
root.addEventListener('pointermove',moveDrag);
root.addEventListener('pointerup',endDrag);
root.addEventListener('pointerleave',endDrag);
q('[data-step-dot]').forEach(function(dot){dot.addEventListener('click',function(){applyState(parseInt(dot.getAttribute('data-step-dot')||'0',10));});});
applyState(current);
})();
